local ToolsState = {
    CollectorEnabled = false,
    KeepPrompts      = false,
    AutoCollectFilled = false,
    SelectedRarities = { Secret = false, Godly = false, Exclusive = false },
}

local priorityMap = { Exclusive = 3, Godly = 2, Secret = 1 }

local function findMyPlot()
    local direct = workspace:FindFirstChild("Plot_" .. player.Name)
    if direct then return direct end
    local directDisplay = workspace:FindFirstChild("Plot_" .. player.DisplayName)
    if directDisplay then return directDisplay end
    for _, obj in pairs(workspace:GetChildren()) do
        if obj.Name:sub(1, 5) == "Plot_" then
            local gui = obj:FindFirstChild("PlotOwner")
                and obj.PlotOwner:FindFirstChild("SurfaceGui")
            if gui then
                local nameLabel = gui:FindFirstChild("Name")
                if nameLabel and (nameLabel.Text == player.Name or nameLabel.Text == player.DisplayName) then
                    return obj
                end
            end
        end
    end
end

local function collectMyPlot()
    local plot = findMyPlot()
    if not plot then return end
    local char = player.Character
    local root = char and char:FindFirstChild("HumanoidRootPart")
    if not root then return end
    for _, floor in pairs(plot:GetChildren()) do
        if floor.Name:sub(1, 5) == "Floor" then
            local slots = floor:FindFirstChild("Slots")
            if not slots then continue end
            for _, slot in pairs(slots:GetChildren()) do
                local touch = slot:FindFirstChild("CollectButton")
                    and slot.CollectButton:FindFirstChild("Touch")
                if touch then
                    pcall(function()
                        firetouchinterest(touch, root, 0)
                        task.wait(0.05)
                        firetouchinterest(touch, root, 1)
                    end)
                end
            end
        end
    end
end

local function collectFilledSlots()
    local plot = workspace:FindFirstChild("Plot_" .. player.Name)
        or workspace:FindFirstChild("Plot_" .. player.DisplayName)
    local char = player.Character
    local root = char and char:FindFirstChild("HumanoidRootPart")
    if not plot or not root then return end

    -- Equip everything in backpack first
    local backpack = player.Backpack
    for _, tool in pairs(backpack:GetChildren()) do
        if tool:IsA("Tool") then
            tool.Parent = char
        end
    end

    for _, floor in pairs(plot:GetChildren()) do
        if floor.Name:sub(1, 5) == "Floor" then
            local slots = floor:FindFirstChild("Slots")
            if not slots then continue end
            for _, slot in pairs(slots:GetChildren()) do
                local spawn = slot:FindFirstChild("Spawn")
                if not spawn then continue end
                local hasItem = spawn:FindFirstChild("VisualItem")
                local prompt  = spawn:FindFirstChild("ProximityPrompt")
                if hasItem and prompt then
                    root.CFrame = CFrame.new(spawn.Position + Vector3.new(0, 4, 0))
                    task.wait(0.2)
                    pcall(function() fireproximityprompt(prompt) end)
                    task.wait(0.3)
                end
            end
        end
    end

    -- Collect money after grabbing all items
    collectMyPlot()
end

local CollectorGroup = Tabs.Tools:AddLeftGroupbox("희귀도 수집기 ")
local BaseToolsGroup = Tabs.Tools:AddRightGroupbox("모두 잠금 해제 / 불사 ")

