})

CollectorGroup:AddToggle("CollectorEnabled", {
    Text    = "자동 즉시 수집 ",
    Default = false,
    Callback = function(v)
        ToolsState.CollectorEnabled = v
        if v then
            -- Auto unlock all bases when collector starts
            for _, base in pairs(workspace.Bases:GetChildren()) do
                local walls  = base:FindFirstChild("Walls")
                local lasers = base:FindFirstChild("Lasers")
                if walls  then walls:Destroy()  end
                if lasers then lasers:Destroy() end
            end
            for _, npc in pairs(workspace.LocalNPCs:GetChildren()) do
                npc:Destroy()
            end
            Library:Notify({ Title = "불사 ", Description = "모든 기지가 잠금 해제되었습니다.", Time = 3 })
            task.spawn(function()
                while ToolsState.CollectorEnabled do
                    local results = {}
                    for _, base in pairs(workspace.Bases:GetChildren()) do
                        local slots = base:FindFirstChild("Slots")
                        if not slots then continue end
                        for _, slot in pairs(slots:GetChildren()) do
                            local spawn       = slot:FindFirstChild("Spawn")
                            local spawnedItem = spawn and spawn:FindFirstChild("SpawnedItem")
                            local part        = spawnedItem and spawnedItem:FindFirstChild("Part")
                            local textLabels  = spawnedItem
                                and spawnedItem:FindFirstChild("InfoGUI")
                                and spawnedItem.InfoGUI:FindFirstChild("TextLabels")
                            local rarityLabel = textLabels and textLabels:FindFirstChild("Rarity")
                            if not (rarityLabel and part) then continue end
                            local rarityText = rarityLabel.Text:lower()
                            for rarity, priority in pairs(priorityMap) do
                                if ToolsState.SelectedRarities[rarity] and rarityText:find(rarity:lower()) then
                                    table.insert(results, { part = part, priority = priority })
                                    break
                                end
                            end
                        end
                    end
                    table.sort(results, function(a, b) return a.priority > b.priority end)
                    local char = player.Character
                    local root = char and char:FindFirstChild("HumanoidRootPart")
                    if root and #results > 0 then
                        for i = 1, math.min(3, #results) do
                            local part = results[i].part
                            root.CFrame = CFrame.new(part.Position + Vector3.new(0, 5, 0))
                            task.wait(0.3)
                            local prompt = part:FindFirstChild("ProximityPrompt")
                            if prompt then pcall(function() fireproximityprompt(prompt) end) end
                            task.wait(1)
                            local returnPart = workspace:FindFirstChild("Map") and workspace.Map:FindFirstChild("Part")
                            if returnPart then
                                root.CFrame = returnPart.CFrame + Vector3.new(0, 5, 0)
                            end
                            task.wait(0.5)
                        end
                    end
                    task.wait(1)
                end
            end)
        end
    end,
})

local promptConnection = nil

BaseToolsGroup:AddButton({
    Text = "모든 기지 잠금 해제(불사) ",
    Func = function()
        for _, base in pairs(workspace.Bases:GetChildren()) do
            local walls  = base:FindFirstChild("Walls")
            local lasers = base:FindFirstChild("Lasers")
            if walls  then walls:Destroy()  end
            if lasers then lasers:Destroy() end
        end
        for _, npc in pairs(workspace.LocalNPCs:GetChildren()) do
            npc:Destroy()
        end
        -- Steal Anything: force all prompts open
        ToolsState.KeepPrompts = true
        task.spawn(function()
            while ToolsState.KeepPrompts do
                for _, base in pairs(workspace.Bases:GetChildren()) do
                    local slots = base:FindFirstChild("Slots")
                    if not slots then continue end
                    for _, slot in pairs(slots:GetChildren()) do
                        local prompt = slot:FindFirstChild("Spawn")
                            and slot.Spawn:FindFirstChild("SpawnedItem")
                            and slot.Spawn.SpawnedItem:FindFirstChild("Part")
                            and slot.Spawn.SpawnedItem.Part:FindFirstChild("ProximityPrompt")
                        if prompt then
                            prompt.Enabled = true
                            prompt.MaxActivationDistance = 20
                            prompt.RequiresLineOfSight = false
                        end
                    end
                end
                task.wait(1)
            end
        end)
        if promptConnection then promptConnection:Disconnect() end
        promptConnection = workspace.DescendantAdded:Connect(function(desc)
            if ToolsState.KeepPrompts and desc:IsA("ProximityPrompt") then
                task.wait(0.1)
                desc.Enabled = true
                desc.MaxActivationDistance = 20
                desc.RequiresLineOfSight = false
            end
        end)
        Library:Notify({ Title = "불사 ", Description = "모든 기지가 잠금 해제되었습니다.", Time = 3 })
    end,
})

